const baseUrl = '{{SUPABASE_URL}}';
const serviceKey = '{{SUPABASE_SERVICE_KEY}}';
const headers = {
  'apikey': serviceKey,
  'Authorization': 'Bearer ' + serviceKey,
  'Content-Type': 'application/json'
};

// Load Google Places API key from template_credentials
const creds = await helpers.httpRequest({
  method: 'GET',
  url: baseUrl + '/rest/v1/template_credentials?template_id=eq.google-reviews&cred_key=eq.google_places_api_key&select=cred_value',
  headers
});

if (!creds || creds.length === 0 || !creds[0].cred_value) {
  return [{ json: { error: 'No Google Places API key configured. Install google-reviews template first.' } }];
}
const apiKey = creds[0].cred_value;

// Load member businesses with Google Place IDs
const businesses = await helpers.httpRequest({
  method: 'GET',
  url: baseUrl + '/rest/v1/member_businesses?select=id,name,google_place_id&active=eq.true&google_place_id=not.is.null',
  headers
});

if (!businesses || businesses.length === 0) {
  return [{ json: { result: 'No businesses with Google Place IDs found.', imported: 0 } }];
}

let totalImported = 0;
let criticalReviews = [];

for (const biz of businesses) {
  try {
    // Fetch reviews from Google Places API (New)
    const placeDetails = await helpers.httpRequest({
      method: 'GET',
      url: 'https://maps.googleapis.com/maps/api/place/details/json'
        + '?place_id=' + encodeURIComponent(biz.google_place_id)
        + '&fields=reviews'
        + '&language=de'
        + '&key=' + apiKey
    });

    const reviews = placeDetails.result && placeDetails.result.reviews;
    if (!reviews || reviews.length === 0) continue;

    for (const review of reviews) {
      // Use author_url as unique identifier (Google doesn't provide review IDs)
      const reviewId = (review.author_url || review.author_name || '') + '_' + review.time;

      // Upsert review
      try {
        await helpers.httpRequest({
          method: 'POST',
          url: baseUrl + '/rest/v1/reviews',
          headers: { ...headers, 'Prefer': 'resolution=merge-duplicates,return=minimal' },
          body: JSON.stringify({
            business_id: biz.id,
            google_review_id: reviewId,
            author: review.author_name || 'Anonym',
            rating: review.rating,
            text: review.text || '',
            published_at: new Date(review.time * 1000).toISOString(),
            fetched_at: new Date().toISOString()
          })
        });
        totalImported++;

        // Track critical reviews (≤3 stars)
        if (review.rating <= 3) {
          criticalReviews.push({
            business: biz.name,
            rating: review.rating,
            author: review.author_name || 'Anonym',
            text: (review.text || '').substring(0, 100)
          });
        }
      } catch(e) {
        // Duplicate — skip silently
      }
    }
  } catch(e) {
    // API error for this business — continue with next
  }
}

return [{ json: {
  result: 'Review-Import abgeschlossen',
  businesses_checked: businesses.length,
  reviews_imported: totalImported,
  critical_reviews: criticalReviews
} }];

const data = $input.first().json;
const reviews = data.critical_reviews;

let msg = '⚠️ *Neue kritische Bewertungen!*\n\n';
for (const r of reviews) {
  msg += '• *' + r.business + '*: ' + '⭐'.repeat(r.rating) + '\n';
  msg += '  Von: ' + r.author + '\n';
  if (r.text) msg += '  _"' + r.text + '"_\n';
  msg += '\n';
}
msg += 'Insgesamt ' + data.reviews_imported + ' Reviews importiert von ' + data.businesses_checked + ' Betrieben.';

return [{ json: { message: msg } }];
